// Composable search filter with GraphQL sync
function useSearchFilters() {
  const route = useRoute();
  const filters = reactive<SearchFilters>({
    query: route.query.q as string ?? '',
    skills: parseArray(route.query.skills),
    budget: parseBudgetRange(route.query.budget),
    sortBy: (route.query.sort as SortOption) ?? 'relevance',
  });

  const { result, loading } = useQuery<SearchResult>(
    SEARCH_JOBS_QUERY,
    () => toGraphQLVariables(filters),
    { debounce: 300 }
  );

  watch(filters, (newFilters) => {
    router.replace({ query: toURLParams(newFilters) });
  }, { deep: true });

  return { filters, result, loading };
}

# Smart dispatch algorithm
class DispatchEngine:
    def find_optimal_driver(
        self, delivery: Delivery
    ) -> Optional[Driver]:
        available = Driver.objects.filter(
            status=DriverStatus.AVAILABLE,
            current_load__lt=F('max_capacity'),
        )
        scored = []
        for driver in available:
            distance = calc_distance(
                driver.location, delivery.pickup
            )
            score = (
                (1 / max(distance, 0.1)) * 0.5
                + driver.reliability_score * 0.3
                + (1 - driver.current_load
                   / driver.max_capacity) * 0.2
            )
            scored.append((driver, score))

        scored.sort(key=lambda x: x[1], reverse=True)
        return scored[0][0] if scored else None

